// The milestone-2 scene from Swift, on the kaya bindings: KayaWire.swift
// (generated by kaya-bindgen from kaya::spec) carries the KayaTx packers
// and the occurrence parser; the kaya C declarations come from kaya.h
// via -import-objc-header. What remains here is the scene declaration
// and the logic answering occurrences.
//
// Swift's main thread enters kaya_run() and becomes the core's UI
// thread; a Thread is the app thread.

import Foundation

// Guest-allocated ids, counted from 1 per space.
let sigStatus: UInt64 = 1
let sigExtras: UInt64 = 2
let wColumn: UInt64 = 1
let wStep: UInt64 = 2
let wStatus: UInt64 = 3
let wWhen: UInt64 = 4
let wGroups: UInt64 = 5
let cGroups: UInt64 = 1
let cItems: UInt64 = 2
let nBanner: UInt64 = 1
let nGroupCol: UInt64 = 2
let nGroupLbl: UInt64 = 3
let nItemsFor: UInt64 = 4
let nItemRow: UInt64 = 5
let nItemText: UInt64 = 6
let nRemove: UInt64 = 7

func buildScene() {
    var tx = KayaTx()
    tx.createSignal(sigStatus, .str("step 0"))
    tx.createSignal(sigExtras, .bool(false))
    tx.createWidget(wColumn, UInt32(KAYA_KIND_COLUMN))
    tx.createWidget(wStep, UInt32(KAYA_KIND_BUTTON))
    tx.setText(wStep, "step")
    tx.createWidget(wStatus, UInt32(KAYA_KIND_LABEL))
    tx.bindText(wStatus, sigStatus)

    // When(extras): a banner label.
    tx.createWhen(wWhen, sigExtras)
    tx.createWidget(nBanner, UInt32(KAYA_KIND_LABEL))
    tx.setText(nBanner, "extras on")
    tx.templateEnd()

    // For over groups, nesting a For over items.
    tx.createCollection(cGroups)
    tx.createFor(wGroups, cGroups)
    tx.createWidget(nGroupCol, UInt32(KAYA_KIND_COLUMN))
    tx.createWidget(nGroupLbl, UInt32(KAYA_KIND_LABEL))
    tx.bindTextElement(nGroupLbl)
    tx.addChild(nGroupCol, nGroupLbl)
    tx.createCollection(cItems)
    tx.createFor(nItemsFor, cItems)
    tx.createWidget(nItemRow, UInt32(KAYA_KIND_COLUMN))
    tx.createWidget(nItemText, UInt32(KAYA_KIND_LABEL))
    tx.bindTextElement(nItemText)
    tx.createWidget(nRemove, UInt32(KAYA_KIND_BUTTON))
    tx.setText(nRemove, "remove")
    tx.addChild(nItemRow, nItemText)
    tx.addChild(nItemRow, nRemove)
    tx.templateEnd()
    tx.addChild(nGroupCol, nItemsFor)
    tx.templateEnd()

    tx.addChild(wColumn, wStep)
    tx.addChild(wColumn, wStatus)
    tx.addChild(wColumn, wWhen)
    tx.addChild(wColumn, wGroups)
    tx.mount(0, wColumn) // window 0: the default
    tx.submit()
}

let appThread = Thread {
    buildScene()
    var steps = 0
    var buf = [UInt8](repeating: 0, count: 256)
    while true {
        let size = buf.withUnsafeMutableBufferPointer { p in
            kaya_next_occurrence(p.baseAddress, 256)
        }
        if size == 0 { break } // shutdown
        guard let (id, keys) = kayaParseClick(buf) else { continue }
        if keys.isEmpty && id == wStep {
            steps += 1
            var tx = KayaTx()
            if steps == 1 {
                tx.collectionInsert(cGroups, [], .str("g1"), .str("Work"))
                tx.collectionInsert(cItems, [.str("g1")], .str("a"), .str("send report"))
                tx.collectionInsert(cItems, [.str("g1")], .str("b"), .str("buy milk"))
            } else if steps == 2 {
                tx.collectionInsert(cGroups, [], .str("g2"), .str("Home"))
                tx.collectionInsert(cItems, [.str("g2")], .str("a"), .str("water plants"))
                tx.collectionUpdate(cGroups, [], .str("g1"), .str("Office"))
            }
            tx.writeSignal(sigExtras, .bool(steps == 1))
            tx.writeSignal(sigStatus, .str("step \(steps)"))
            tx.submit()
        } else if keys.count == 2, id == nRemove,
            case .str(let group) = keys[0], case .str(let item) = keys[1]
        {
            var tx = KayaTx()
            tx.collectionRemove(cItems, [.str(group)], .str(item))
            tx.writeSignal(sigStatus, .str("removed \(group)/\(item)"))
            tx.submit()
        }
    }
}
appThread.start()

// Takes over the main thread; on iOS this never returns (the self-test
// exits the process).
exit(kaya_run())
